464	//                           StkId res, TMS event)
465	/// Try to find and call a binary tag method for `event`.
466	///
467	/// Checks `p1` first, then `p2`, for a metamethod.  If neither has one,
468	/// returns `false` and leaves `res` unmodified.  If found, calls it with
469	/// `(p1, p2)` as arguments, writes the result to slot `res`, and returns `true`.
470	fn call_bin_tm(
471	    state: &mut LuaState,
472	    p1: &LuaValue,
473	    p2: &LuaValue,
474	    res: StackIdx,
475	    event: TagMethod,
476	) -> Result<bool, LuaError> {
477	    // C: const TValue *tm = luaT_gettmbyobj(L, p1, event);  /* try first operand */
478	    let tm = get_tm_by_obj(state, p1, event);
479	    // C: if (notm(tm))
480	    //      tm = luaT_gettmbyobj(L, p2, event);  /* try second operand */
481	    let tm = if tm.is_nil() {
482	        get_tm_by_obj(state, p2, event)
483	    } else {
484	        tm
485	    };
486	    // C: if (notm(tm)) return 0;
487	    if tm.is_nil() {
488	        return Ok(false);
489	    }
490	    // C: luaT_callTMres(L, tm, p1, p2, res);
491	    // Clone p1/p2 before the mutable borrow of `state` via call_tm_res.
492	    call_tm_res(state, tm, p1.clone(), p2.clone(), res)?;
493	    // C: return 1;
494	    Ok(true)
495	}
