499	// C: void luaT_trybinTM (lua_State *L, const TValue *p1, const TValue *p2,
500	//                         StkId res, TMS event)
501	/// Attempt a binary metamethod call; raise a type error if no metamethod exists.
502	///
503	/// For bitwise operations, further distinguishes between:
504	/// - Both operands are numbers but not integers → `LuaError::int_overflow`
505	///   (`luaG_tointerror` — "number has no integer representation")
506	/// - At least one operand is not a number → `LuaError::arith_error` with
507	///   "perform bitwise operation on"
508	///
509	/// All other missing metamethods raise `LuaError::arith_error` with
510	/// "perform arithmetic on".
511	pub(crate) fn try_bin_tm(
512	    state: &mut LuaState,
513	    p1: &LuaValue,
514	    p2: &LuaValue,
515	    res: StackIdx,
516	    event: TagMethod,
517	) -> Result<(), LuaError> {
518	    // C: if (l_unlikely(!callbinTM(L, p1, p2, res, event))) {
519	    if !call_bin_tm(state, p1, p2, res, event)? {
520	        // C: switch (event) {
521	        //   case TM_BAND: case TM_BOR: case TM_BXOR:
522	        //   case TM_SHL: case TM_SHR: case TM_BNOT: {
523	        //     if (ttisnumber(p1) && ttisnumber(p2))
524	        //       luaG_tointerror(L, p1, p2);
525	        //     else
526	        //       luaG_opinterror(L, p1, p2, "perform bitwise operation on");
527	        //   }
528	        //   /* calls never return, but to avoid warnings: *//* FALLTHROUGH */
529	        //   default:
530	        //     luaG_opinterror(L, p1, p2, "perform arithmetic on");
531	        // }
532	        //
533	        // PORT NOTE: the C switch has a dead "FALLTHROUGH" for bitwise cases
534	        // because both branches of the inner if/else call noreturn functions.
535	        // In Rust `match` has no implicit fallthrough; each arm is self-contained
536	        // and explicitly returns `Err(...)`.
537	        match event {
538	            TagMethod::BAnd
539	            | TagMethod::BOr
540	            | TagMethod::BXor
541	            | TagMethod::Shl
542	            | TagMethod::Shr
543	            | TagMethod::BNot => {
544	                // C: if (ttisnumber(p1) && ttisnumber(p2))
545	                if matches!(p1, LuaValue::Int(_) | LuaValue::Float(_))
546	                    && matches!(p2, LuaValue::Int(_) | LuaValue::Float(_))
547	                {
548	                    // C: luaG_tointerror(L, p1, p2)
549	                    return Err(LuaError::int_overflow(p1, p2));
550	                } else {
551	                    // C: luaG_opinterror(L, p1, p2, "perform bitwise operation on")
552	                    return Err(LuaError::arith_error(p1, p2, "perform bitwise operation on"));
553	                }
554	            }
555	            _ => {
556	                // C: luaG_opinterror(L, p1, p2, "perform arithmetic on")
557	                return Err(LuaError::arith_error(p1, p2, "perform arithmetic on"));
558	            }
559	        }
560	    }
561	    Ok(())
562	}
