567	/// Attempt the `__concat` metamethod on the two values at the top of the stack.
568	///
569	/// Reads `stack[top-2]` and `stack[top-1]`, searches both for `__concat`,
570	/// calls it with `(stack[top-2], stack[top-1])` writing the result back to
571	/// `stack[top-2]`, or raises `LuaError::concat_error` if no metamethod exists.
572	pub(crate) fn try_concat_tm(state: &mut LuaState) -> Result<(), LuaError> {
573	    // C: StkId top = L->top.p;
574	    let top = state.top_idx();
575	    // C: if (l_unlikely(!callbinTM(L, s2v(top - 2), s2v(top - 1), top - 2, TM_CONCAT)))
576	    //      luaG_concaterror(L, s2v(top - 2), s2v(top - 1));
