578	    // Clone the operands before any call that might mutate the stack.
579	    let p1 = state.get_at(top - 2).clone();
580	    let p2 = state.get_at(top - 1).clone();
581	    if !call_bin_tm(state, &p1, &p2, top - 2, TagMethod::Concat)? {
582	        // C: luaG_concaterror(L, s2v(top - 2), s2v(top - 1))
