    pub fn upvalue_get(&self, cl: &GcRef<LuaClosureLua>, n: usize) -> LuaValue {
        let uv = &cl.upvals[n];
        match uv.as_ref() {
            UpVal::Closed(v) => v.clone(),
            UpVal::Open { thread_id: _, idx } => self.stack[idx.0 as usize].val.clone(),
